+<body>
+    <h1>LanceQL Browser Demo <span class="version" id="version"></span></h1>
+
+    <div class="card">
+        <h2>Load Lance File</h2>
+        <div class="drop-zone" id="drop-zone">
+            <p>Drop a .lance data file here or click to select</p>
+            <p style="font-size: 12px; color: #666;">Navigate into dataset_name.lance/data/ and select the hex-named .lance file</p>
+            <input type="file" id="file-input">
+        </div>
+        <div id="status"></div>
+    </div>
+
+    <div class="card" id="results">
+        <h2>File Info</h2>
+        <table id="info-table">
+            <tr>
+                <th>Property</th>
+                <th>Value</th>
+            </tr>
+        </table>
+
+        <h2>Columns</h2>
+        <div id="columns"></div>
+    </div>
+
+    <script type="module">
+        import LanceQL from './lanceql.js';
+
+        let lanceql;
+
+        async function init() {
+            try {
+                lanceql = await LanceQL.load('./lanceql.wasm');
+                document.getElementById('version').textContent = `v${lanceql.getVersion()}`;
+                console.log('LanceQL loaded:', lanceql.getVersion());
+            } catch (err) {
+                document.getElementById('status').textContent = 'Failed to load WASM: ' + err.message;
+                console.error(err);
+            }
+        }
+
+        function handleFile(file) {
+            const status = document.getElementById('status');
+            status.textContent = `Loading ${file.name}...`;
+
+            const reader = new FileReader();
+            reader.onload = (e) => {
+                try {
+                    processLanceFile(e.target.result, file.name);
+                } catch (err) {
+                    status.innerHTML = `<span class="badge" style="background:#f8d7da;color:#721c24">Error: ${err.message}</span>`;
+                    console.error('processLanceFile error:', err);
+                }
+            };
+            reader.onerror = () => {
+                status.innerHTML = `<span class="badge" style="background:#f8d7da;color:#721c24">Failed to read file</span>`;
+            };
+            reader.readAsArrayBuffer(file);
+        }
+
+        function processLanceFile(data, filename) {
+            const status = document.getElementById('status');
+
+            // Check if valid
+            if (!lanceql.isValid(data)) {
+                status.innerHTML = `<span class="badge" style="background:#f8d7da;color:#721c24">Invalid Lance file - missing LANC magic bytes</span>`;
+                document.getElementById('results').style.display = 'none';
+                return;
+            }
+
+            // Open file
+            const file = lanceql.open(data);
+
+            try {
+                status.innerHTML = `<span class="badge badge-success">Loaded successfully</span>`;
+
+                // Show results
+                document.getElementById('results').style.display = 'block';
+
+                // File info
+                const infoTable = document.getElementById('info-table');
+                infoTable.innerHTML = `
+                    <tr><th>Property</th><th>Value</th></tr>
+                    <tr><td>Filename</td><td>${filename}</td></tr>
+                    <tr><td>Size</td><td>${(data.byteLength / 1024).toFixed(2)} KB</td></tr>
+                    <tr><td>Columns</td><td>${file.numColumns}</td></tr>
+                `;
+
+                // Columns
+                const columnsDiv = document.getElementById('columns');
+                columnsDiv.innerHTML = '';
+
+                for (let i = 0; i < file.numColumns; i++) {
+                    const debug = file.getColumnDebugInfo(i);
+                    const rowCount = Number(debug.rows);
+
+                    // Try to read as int64 first, then float64
+                    let values;
+                    let type = 'unknown';
+
+                    try {
+                        const int64Data = file.readInt64Column(i);
+                        if (int64Data.length > 0) {
+                            values = Array.from(int64Data).slice(0, 100).map(v => v.toString());
+                            type = 'int64';
+                        }
+                    } catch (e) {}
+
+                    if (!values) {
+                        try {
+                            const float64Data = file.readFloat64Column(i);
+                            if (float64Data.length > 0) {
+                                values = Array.from(float64Data).slice(0, 100).map(v => v.toFixed(4));
+                                type = 'float64';
+                            }
+                        } catch (e) {}
+                    }
+
+                    const colDiv = document.createElement('div');
+                    colDiv.style.marginBottom = '15px';
+                    colDiv.innerHTML = `
+                        <h3>Column ${i} <span class="badge badge-info">${type}</span></h3>
+                        <p>Rows: ${rowCount.toLocaleString()}</p>
+                        <div class="column-data">${values ? values.join(', ') + (values.length < rowCount ? '...' : '') : 'Could not decode'}</div>
+                    `;
+                    columnsDiv.appendChild(colDiv);
+                }
+
+            } finally {
+                file.close();
+            }
+        }
+
+        // Event handlers
+        const dropZone = document.getElementById('drop-zone');
+        const fileInput = document.getElementById('file-input');
+
+        dropZone.addEventListener('click', () => fileInput.click());
+        dropZone.addEventListener('dragover', (e) => {
+            e.preventDefault();
+            dropZone.classList.add('dragover');
+        });
+        dropZone.addEventListener('dragleave', () => {
+            dropZone.classList.remove('dragover');
+        });
+        dropZone.addEventListener('drop', (e) => {
+            e.preventDefault();
+            dropZone.classList.remove('dragover');
+            const file = e.dataTransfer.files[0];
+            if (file) handleFile(file);
+        });
+        fileInput.addEventListener('change', () => {
+            const file = fileInput.files[0];
+            if (file) handleFile(file);
+        });
+
+        // Initialize
+        init();
+    </script>
+</body>
+</html>

